                                    </label>
                                    <label style={{ display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer', fontSize: '11px', fontWeight: '500', marginTop: '4px', borderTop: '1px dashed rgba(0,0,0,0.1)', paddingTop: '6px' }}>
