                            <h3 style={{ fontSize: '18px', fontWeight: '700', color: 'var(--text-main)', margin: '0 0 8px 0' }}>Aucune anomalie d├®tect├®e !</h3>
                            <p style={{ fontSize: '14px', color: 'var(--text-muted)', margin: 0, maxWidth: '400px', display: 'inline-block' }}>Toutes les p├®riodes d'abonnement sont factur├®es et la num├®rotation suit une s├®quence parfaite.</p>
                        </div>
                    ) : (
                        <>
                            {/* SECTION 1: MENSUALIT├ëS OUBLI├ëES */}
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px', borderBottom: '2px solid var(--border-color)', paddingBottom: '12px' }}>
                                    <div style={{ width: '32px', height: '32px', borderRadius: '8px', background: 'rgba(239, 68, 68, 0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#EF4444' }}>
