import React, { useState, useEffect } from 'react';
import { X, UserPlus, Save, Briefcase, Calendar, Percent, ListTodo, User } from 'lucide-react';

const RHFormModal = ({ isOpen, onClose, onSave, initialData, projetsDisponibles }) => {
    const [formData, setFormData] = useState({
        id: '',
        nom: '',
        poste: '',
        dateDebut: '',
        taches: ''
    });

    useEffect(() => {
        if (isOpen) {
            if (initialData) {
                setFormData({ ...initialData, actif: initialData.actif !== false });
            } else {
                setFormData({
                    id: `RH_${Date.now()}`,
                    nom: '',
                    poste: '',
                    dateDebut: new Date().toISOString().split('T')[0],
                    taches: '',
                    actif: true
                });
            }
        }
    }, [isOpen, initialData]);

    if (!isOpen) return null;

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        onSave(formData);
        onClose();
    };

    return (
        <div style={{
            position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
            backgroundColor: 'rgba(15, 23, 42, 0.75)',
            backdropFilter: 'blur(8px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            zIndex: 1000, padding: '20px'
        }}>
            <div style={{
                background: 'var(--card-bg)',
                borderRadius: '24px',
                width: '100%',
                maxWidth: '650px',
                boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)',
                border: '1px solid var(--border-color)',
                display: 'flex', flexDirection: 'column',
                maxHeight: '90vh',
                animation: 'slideUp 0.3s ease-out'
            }}>
                {/* HEADER */}
                <div style={{
                    padding: '24px 32px',
                    borderBottom: '1px solid var(--border-color)',
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    background: 'var(--bg-main)',
                    borderTopLeftRadius: '24px', borderTopRightRadius: '24px'
                }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                        <div style={{
                            width: '48px', height: '48px', borderRadius: '16px',
                            background: 'rgba(255, 193, 5, 0.1)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: 'var(--accent-gold)'
                        }}>
                            {initialData ? <Save size={24} /> : <UserPlus size={24} />}
                        </div>
                        <div>
                            <h2 style={{ margin: 0, fontSize: '20px', fontWeight: '800', color: 'var(--text-main)' }}>
                                {initialData ? 'Modifier Collaborateur' : 'Nouveau Collaborateur'}
                            </h2>
                            <p style={{ margin: '4px 0 0', fontSize: '13px', color: 'var(--text-muted)' }}>
                                Renseignez les informations de la ressource humaine
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} style={{
                        background: 'transparent', border: 'none', cursor: 'pointer',
                        color: 'var(--text-muted)', padding: '8px', borderRadius: '50%',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        transition: 'background 0.2s'
                    }} onMouseOver={e => e.currentTarget.style.background = 'rgba(255,255,255,0.05)'} onMouseOut={e => e.currentTarget.style.background = 'transparent'}>
                        <X size={20} />
                    </button>
                </div>

                {/* CONTENT */}
                <div style={{ padding: '32px', overflowY: 'auto' }}>
                    <form id="rh-form" onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>

                        {/* ROW 1: Nom & Poste */}
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                            <div>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', fontWeight: '600', color: 'var(--text-secondary)', marginBottom: '8px' }}>
                                    <User size={14} /> Nom & Pr├®nom *
                                </label>
                                <input
                                    required
                                    type="text"
                                    name="nom"
                                    value={formData.nom}
                                    onChange={handleChange}
                                    placeholder="Ex: Ahmed Ben Ali"
                                    style={{
                                        width: '100%', padding: '12px 16px', borderRadius: '12px',
                                        border: '1px solid var(--border-color)', background: 'var(--bg-main)',
                                        color: 'var(--text-main)', fontSize: '14px', outline: 'none',
                                        transition: 'border-color 0.2s',
                                        boxSizing: 'border-box'
                                    }}
                                />
                            </div>
                            <div>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', fontWeight: '600', color: 'var(--text-secondary)', marginBottom: '8px' }}>
                                    <Briefcase size={14} /> Poste / R├┤le *
                                </label>
                                <input
                                    required
                                    type="text"
                                    name="poste"
                                    value={formData.poste}
                                    onChange={handleChange}
                                    placeholder="Ex: UI/UX Designer"
                                    style={{
                                        width: '100%', padding: '12px 16px', borderRadius: '12px',
                                        border: '1px solid var(--border-color)', background: 'var(--bg-main)',
                                        color: 'var(--text-main)', fontSize: '14px', outline: 'none',
                                        transition: 'border-color 0.2s',
                                        boxSizing: 'border-box'
                                    }}
                                />
                            </div>
                        </div>

                        {/* ROW 2: Statut */}
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginBottom: '24px' }}>
                            <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', fontWeight: '600', color: 'var(--text-secondary)' }}>
                                Statut (G├®n├®ration de Paie)
                            </label>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: '600', color: 'var(--text-main)' }}>
                                    <input type="radio" name="actif" value="true" checked={formData.actif === true} onChange={() => setFormData(prev => ({ ...prev, actif: true }))} />
                                    Actif
                                </label>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: '600', color: 'var(--text-muted)' }}>
                                    <input type="radio" name="actif" value="false" checked={formData.actif === false} onChange={() => setFormData(prev => ({ ...prev, actif: false }))} />
                                    Inactif
                                </label>
                            </div>
                        </div>

                        {/* ROW 3: Date & Taches */}
                        <div style={{ display: 'grid', gridTemplateColumns: 'minmax(200px, 1fr) 2fr', gap: '20px' }}>
                            <div>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', fontWeight: '600', color: 'var(--text-secondary)', marginBottom: '8px' }}>
                                    <Calendar size={14} /> Prise de Projet
                                </label>
                                <input
                                    type="date"
                                    name="dateDebut"
                                    value={formData.dateDebut}
                                    onChange={handleChange}
                                    style={{
                                        width: '100%', padding: '12px 16px', borderRadius: '12px',
                                        border: '1px solid var(--border-color)', background: 'var(--bg-main)',
                                        color: 'var(--text-main)', fontSize: '14px', outline: 'none',
                                        boxSizing: 'border-box'
                                    }}
                                />
                            </div>
                            <div>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', fontWeight: '600', color: 'var(--text-secondary)', marginBottom: '8px' }}>
                                    <ListTodo size={14} /> T├óches assign├®es
                                </label>
                                <textarea
                                    name="taches"
                                    value={formData.taches}
                                    onChange={handleChange}
                                    placeholder="D├®crivez les t├óches sp├®cifiques pour ce projet..."
                                    rows={3}
                                    style={{
                                        width: '100%', padding: '12px 16px', borderRadius: '12px',
                                        border: '1px solid var(--border-color)', background: 'var(--bg-main)',
                                        color: 'var(--text-main)', fontSize: '14px', outline: 'none',
                                        resize: 'vertical', minHeight: '80px', fontFamily: 'inherit',
                                        boxSizing: 'border-box'
                                    }}
                                />
                            </div>
                        </div>

                    </form>
                </div>

                {/* FOOTER */}
                <div style={{
                    padding: '24px 32px',
                    borderTop: '1px solid var(--border-color)',
                    background: 'var(--bg-main)',
                    borderBottomLeftRadius: '24px', borderBottomRightRadius: '24px',
                    display: 'flex', justifyContent: 'flex-end', gap: '16px'
                }}>
                    <button
                        type="button"
                        onClick={onClose}
                        style={{
                            padding: '12px 24px', borderRadius: '12px',
                            background: 'transparent', border: '1px solid var(--border-color)',
                            color: 'var(--text-main)', fontWeight: '600', cursor: 'pointer',
                            transition: 'all 0.2s'
                        }}
                    >
                        Annuler
                    </button>
                    <button
                        form="rh-form"
                        type="submit"
                        style={{
                            padding: '12px 32px', borderRadius: '12px',
                            background: 'var(--text-main)', border: 'none',
                            color: 'white', fontWeight: '700', cursor: 'pointer',
                            display: 'flex', alignItems: 'center', gap: '8px',
                            boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                            transition: 'transform 0.2s'
                        }}
                        onMouseOver={e => e.currentTarget.style.transform = 'translateY(-2px)'}
                        onMouseOut={e => e.currentTarget.style.transform = 'translateY(0)'}
                    >
                        {initialData ? 'Mettre ├á jour' : 'Ajouter au catalogue'}
                    </button>
                </div>
            </div>
            <style>
                {`
                    @keyframes slideUp {
                        from { opacity: 0; transform: translateY(20px); }
                        to { opacity: 1; transform: translateY(0); }
                    }
                `}
            </style>
        </div>
    );
};

export default RHFormModal;

import React, { useState, useEffect } from 'react';
import { AlertTriangle, Clock, Send, ShieldAlert, CalendarClock } from 'lucide-react';
import { getClients, getFactures } from '../services/storageService';

const ScrollingBanner = () => {
    const [alerts, setAlerts] = useState([]);

    useEffect(() => {
        const calculateAlerts = () => {
            const newAlerts = [];

            // 1. Load Data
            let clients = [];
            let factures = [];
            try {
                clients = getClients();
                factures = getFactures();
            } catch (e) {
                console.error("Error loading data for banner", e);
                return;
            }

            const now = new Date();
            const currentYear = now.getFullYear();
            const currentMonth = now.getMonth();

            // 2. Contrats ├á envoyer (Active Abonnements without explicit cycle tracking or missing initial contract)
            // Simplified logic: Active Abonnements that don't have a 'dateDebut' set, meaning they are active but lack formal start tracking
            const contratsAEnvoyer = clients.filter(c => c.regime === 'Abonnement' && c.etatClient === 'Actif' && !c.dateDebut).length;
            if (contratsAEnvoyer > 0) {
                newAlerts.push({
                    id: 'contrats',
                    label: 'Contrats ├á finaliser',
                    value: contratsAEnvoyer,
                    icon: <ShieldAlert size={14} />,
                    color: 'var(--warning)',
                    bg: 'var(--warning-bg)'
                });
            }

            // 3. Factures non envoy├®es (Drafts)
            const draftFactures = factures.filter(f => f.statut === 'Draft').length;
            if (draftFactures > 0) {
                newAlerts.push({
                    id: 'drafts',
                    label: 'Factures non envoy├®es',
                    value: draftFactures,
                    icon: <Send size={14} />,
                    color: 'var(--text-muted)',
                    bg: 'rgba(100, 116, 139, 0.1)' // Slate transparent
                });
            }

            // 4. En attente de paiement (Sent)
            const sentFactures = factures.filter(f => f.statut === 'Sent').length;
            if (sentFactures > 0) {
                newAlerts.push({
                    id: 'sent',
                    label: 'En attente de paiement',
                    value: sentFactures,
                    icon: <Clock size={14} />,
                    color: 'var(--info)',
                    bg: 'var(--info-bg)'
                });
            }

            // 5. Retard de paiement (Late)
            const lateFactures = factures.filter(f => f.statut === 'Late').length;
            if (lateFactures > 0) {
                newAlerts.push({
                    id: 'late',
                    label: 'Retards de paiement',
                    value: lateFactures,
                    icon: <AlertTriangle size={14} />,
                    color: 'var(--danger)',
                    bg: 'var(--danger-bg)'
                });
            }

            // 6. Prochain paiement (Due in next 7 days)
            const upcomingPayments = factures.filter(f => {
                if (f.statut !== 'Sent' || !f.echeance || f.echeance === 'N/A') return false;
                const dueDate = new Date(f.echeance);
                if (isNaN(dueDate.getTime())) return false;

                const diffTime = dueDate.getTime() - now.getTime();
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
                return diffDays >= 0 && diffDays <= 7;
            }).length;

            if (upcomingPayments > 0) {
                newAlerts.push({
                    id: 'upcoming',
                    label: 'Paiements imminents (7j)',
                    value: upcomingPayments,
                    icon: <CalendarClock size={14} />,
                    color: 'var(--success)',
                    bg: 'var(--success-bg)'
                });
            }

            // If everything is perfect, show a success message so the banner isn't completely empty
            if (newAlerts.length === 0) {
                newAlerts.push({
                    id: 'all-good',
                    label: 'Tout est ├á jour !',
                    value: '0 action requise',
                    icon: <ShieldAlert size={14} />,
                    color: 'var(--success)',
                    bg: 'var(--success-bg)'
                });
            }

            setAlerts(newAlerts);
        };

        calculateAlerts();

        // Optional: set an interval to refresh the banner data periodically (e.g., every 60s)
        const interval = setInterval(calculateAlerts, 60000);
        return () => clearInterval(interval);
    }, []);

    // Duplicate the alerts array to create a seamless infinite loop
    const displayAlerts = [...alerts, ...alerts, ...alerts];

    return (
        <div style={{
            width: '100%',
            overflow: 'hidden',
            background: 'var(--card-bg)',
            border: '1px solid var(--border-color)',
            borderRadius: '16px',
            marginBottom: '24px',
            padding: '10px 0',
            display: 'flex',
            alignItems: 'center',
            boxShadow: '0 4px 12px rgba(0,0,0,0.02)',
            position: 'relative'
        }}>
            {/* Left fade gradient */}
            <div style={{
                position: 'absolute',
                left: 0,
                top: 0,
                bottom: 0,
                width: '40px',
                background: 'linear-gradient(to right, var(--bg-color), transparent)',
                zIndex: 2,
                pointerEvents: 'none',
                borderTopLeftRadius: '16px',
                borderBottomLeftRadius: '16px'
            }}></div>

            {/* The scrolling container */}
            <div className="marquee-container" style={{
                display: 'flex',
                gap: '24px',
                paddingLeft: '24px', /* Initial offset */
            }}>
                {displayAlerts.map((alert, index) => (
                    <div
                        key={`${alert.id}-${index}`}
                        className="marquee-item"
                        style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: '10px',
                            background: alert.bg,
                            padding: '6px 14px',
                            borderRadius: '100px',
                            border: `1px solid ${alert.color}33`, /* 33 is 20% opacity in hex */
                            whiteSpace: 'nowrap',
                            cursor: 'default',
                            transition: 'transform 0.2s, box-shadow 0.2s'
                        }}
                    >
                        <div style={{ color: alert.color, display: 'flex', alignItems: 'center' }}>
                            {alert.icon}
                        </div>
                        <div style={{ fontSize: '12px', fontWeight: '700', color: 'var(--text-main)' }}>
                            {alert.label}
                        </div>
                        <div style={{
                            fontSize: '12px',
                            fontWeight: '800',
                            background: alert.color,
                            color: 'white',
                            padding: '2px 8px',
                            borderRadius: '10px',
                            marginLeft: '4px'
                        }}>
                            {alert.value}
                        </div>
                    </div>
                ))}
            </div>

            {/* Right fade gradient */}
            <div style={{
                position: 'absolute',
                right: 0,
                top: 0,
                bottom: 0,
                width: '40px',
                background: 'linear-gradient(to left, var(--bg-color), transparent)',
                zIndex: 2,
                pointerEvents: 'none',
                borderTopRightRadius: '16px',
                borderBottomRightRadius: '16px'
            }}></div>
        </div>
    );
};

export default ScrollingBanner;

