            const parsed = getClients();
            if (parsed && parsed.length > 0) {
                setClients(parsed);
            }
            setRhList(getStorage('mynds_rh', []));
        };
        window.addEventListener('storage', syncData);
        return () => window.removeEventListener('storage', syncData);
