                                {/* GRID INFO: Dates & Duration (Minimalist) */}
                                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '6px', paddingTop: '8px', borderTop: '1px dashed var(--border-color)', marginTop: '4px' }}>
