                                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                                        <span style={{ fontSize: '9px', color: 'var(--text-muted)', fontWeight: '600' }}>Dur├®e</span>
                                        <span style={{ fontSize: '11px', color: 'var(--text-main)', fontWeight: '500' }}>{client.regime === 'Abonnement' ? (client.dureeService || 'Ôê×') : (`${client.dureeMois} Mo`)}</span>
