                                                        <div style={{ position: 'relative' }}>
                                                            <img src={client.logo} alt="Logo" style={{ width: '28px', height: '28px', borderRadius: '4px', objectFit: 'contain', background: 'white', border: '1px solid var(--border-color)' }} />
                                                            {client.etatClient === 'Actif' && (
                                                                ['enseigne', 'secteur', 'mail', 'telephone', 'projet', 'employeAssocie', 'charge', 'adresse', 'dateDebut', 'regime'].some(f => !client[f] || String(client[f]).trim() === '') || 
                                                                !(client.projectCosts && client.projectCosts.some(cost => cost.nom && cost.montant))
                                                            ) && (
                                                                <div style={{ position: 'absolute', top: '-4px', right: '-4px', width: '10px', height: '10px', background: 'var(--danger)', borderRadius: '50%', border: '2px solid white', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontSize: '8px', fontWeight: 'bold' }} title="Fiche incompl├¿te (Champs obligatoires ou structure de co├╗ts manquants)">i</div>
                                                            )}
                                                        </div>
                                                    ) : (
                                                        <div style={{ width: '28px', height: '28px', borderRadius: '4px', background: 'var(--bg-main)', border: '1px solid var(--border-color)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '11px', fontWeight: '600', color: 'var(--text-muted)', position: 'relative' }}>
                                                            {client.enseigne.substring(0, 2).toUpperCase()}
                                                            {client.etatClient === 'Actif' && (
                                                                ['enseigne', 'secteur', 'mail', 'telephone', 'projet', 'employeAssocie', 'charge', 'adresse', 'dateDebut', 'regime'].some(f => !client[f] || String(client[f]).trim() === '') || 
                                                                !(client.projectCosts && client.projectCosts.some(cost => cost.nom && cost.montant))
                                                            ) && (
                                                                <div style={{ position: 'absolute', top: '-4px', right: '-4px', width: '10px', height: '10px', background: 'var(--danger)', borderRadius: '50%', border: '2px solid white', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontSize: '8px', fontWeight: 'bold' }} title="Fiche incompl├¿te (Champs obligatoires ou structure de co├╗ts manquants)">i</div>
                                                            )}
                                                        </div>
                                                    )}
                                                    <div>
                                                        <div style={{ fontWeight: '600', color: 'var(--text-main)', fontSize: '13px' }}>{client.enseigne}</div>
                                                        <div style={{ fontSize: '10px', color: 'var(--text-muted)' }}>{client.id}</div>
                                                    </div>
                                                </div>
                                            </td>
                                            <td style={{ padding: '8px 16px' }}>
                                                {client.projet && (
                                                    <div style={{ fontSize: '12px', fontWeight: '500', color: 'var(--text-main)', marginBottom: '2px' }}>{client.projet}</div>
                                                )}
                                                <div style={{ fontSize: '11px', color: 'var(--text-muted)' }}>{client.secteur || 'Secteur NC'}</div>
                                            </td>
                                            <td style={{ padding: '8px 16px' }}>
                                                <span style={{ padding: '3px 8px', borderRadius: '100px', fontSize: '10px', fontWeight: '600', background: statusStyle.bg, color: statusStyle.color }}>
                                                    {client.etatClient}
                                                </span>
                                            </td>
                                            <td style={{ padding: '8px 16px' }}>
                                                <span style={{ fontSize: '11px', fontWeight: '600', color: isAbonnement ? 'var(--accent-gold)' : 'var(--text-secondary)', background: isAbonnement ? 'rgba(255,193,5,0.1)' : 'rgba(15,23,42,0.05)', padding: '3px 6px', borderRadius: '4px' }}>
                                                    {client.regime}
                                                </span>
                                            </td>
                                            <td style={{ padding: '8px 16px' }}>
                                                <div style={{ fontSize: '11px', fontWeight: '500', color: 'var(--text-main)' }}>{calculateDuration(client.dateDebut)}</div>
                                            </td>
                                            <td style={{ padding: '8px 16px' }}>
                                                <div style={{ fontWeight: '600', color: 'var(--text-main)', fontSize: '12px' }}>{revenue ? formatMoney(revenue) : '--'}</div>
                                                {client.netMargin !== undefined && (
                                                    <div style={{ fontSize: '11px', fontWeight: '600', color: client.netMargin >= 0 ? 'var(--success)' : 'var(--danger)', marginTop: '2px' }}>
                                                        {client.netMargin > 0 ? '+' : ''}{formatMoney(client.netMargin)} Marge
                                                    </div>
                                                )}
                                            </td>
                                            <td style={{ padding: '8px 16px', textAlign: 'right' }}>
                                                <div style={{ display: 'flex', gap: '4px', justifyContent: 'flex-end' }}>
                                                    <button onClick={() => handleEditClient(client)} style={{ background: 'transparent', border: 'none', borderRadius: '4px', width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'var(--text-muted)' }} title="Modifier">
                                                        <Edit2 size={14} />
                                                    </button>
                                                    <button onClick={() => handleArchiveClient(client.id)} style={{ background: 'transparent', border: 'none', borderRadius: '4px', width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'var(--warning)' }} title="Archiver">
                                                        <Archive size={14} />
                                                    </button>
                                                    <button onClick={() => handleDeleteClient(client.id)} style={{ background: 'transparent', border: 'none', borderRadius: '4px', width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'var(--danger)' }} title="Supprimer">
                                                        <Trash2 size={14} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {
                displayedClients.length === 0 && (
                    <div style={{ padding: '60px 24px', textAlign: 'center', color: 'var(--text-muted)', background: 'var(--card-bg)', borderRadius: '24px', border: '1px dashed var(--border-color)' }}>
                        <p style={{ fontSize: '16px', fontWeight: '500' }}>Aucun client trouv├® pour ce filtre.</p>
                    </div>
                )
            }

            {/* MODAL */}
            <ClientModal
                isOpen={isClientModalOpen}
                onClose={() => { setIsClientModalOpen(false); setEditingClient(null); }}
                onSave={handleSaveClient}
                initialData={editingClient}
            />
        </div >
    );
};

export default ClientsPage;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Header from '../components/Header';
import { Settings, Briefcase, Tag, Users, Plus, Trash2, Edit2, Calendar, HardDrive, Download, Upload } from 'lucide-react';
import { initialSecteurs, initialServices, loadConfig, saveConfig } from '../data/defaultConfig';
import RHFormModal from '../components/RHFormModal';
import { getClients } from '../services/storageService';

const ConfigPage = () => {
    const [activeTab, setActiveTab] = useState('secteurs');

    // Modal state for RH
    const [isRHModalOpen, setIsRHModalOpen] = useState(false);
    const [editingRH, setEditingRH] = useState(null);

    // File input ref for importing backup
    const fileInputRef = useRef(null);

    // DATA FOR SECTEURS & PROJETS
    const [secteurs, setSecteurs] = useState(() => loadConfig('secteurs', initialSecteurs));

    // DATA FOR SERVICES & PRIX
    const [services, setServices] = useState(() => {
        const loaded = loadConfig('services', initialServices);
        return loaded.length > 0 ? loaded : initialServices;
    });

    const [rhList, setRhList] = useState(() => loadConfig('rh', []));

    // STORAGE CALCULATION
    const [storageInfo, setStorageInfo] = useState({ used: 0, mbUsed: 0, max: 5, percentage: 0 });

    useEffect(() => {
        const calculateStorage = () => {
            let total = 0;
            for (let x in localStorage) {
                if (localStorage.hasOwnProperty(x)) {
                    total += (localStorage[x].length + x.length) * 2;
                }
            }
            const mbUsed = total / (1024 * 1024);
            const percentage = Math.min((total / (5 * 1024 * 1024)) * 100, 100);
            setStorageInfo({ used: total, mbUsed: mbUsed.toFixed(2), max: 5, percentage: Math.round(percentage) });
        };
        calculateStorage();
        const interval = setInterval(calculateStorage, 10000);
        return () => clearInterval(interval);
    }, [activeTab]);

    // Auto-save when config changes
    useEffect(() => { saveConfig('secteurs', secteurs); }, [secteurs]);
    useEffect(() => { saveConfig('services', services); }, [services]);
    useEffect(() => { saveConfig('rh', rhList); }, [rhList]);

    // HANDLERS SECTEURS
    const handleAddSecteur = () => {
        const nom = window.prompt("Nom du nouveau secteur d'activit├® :");
        if (nom) setSecteurs([...secteurs, { id: `SEC_${Date.now()}`, nom, projets: [] }]);
    };
    const handleDeleteSecteur = (id) => {
        if (window.confirm("Supprimer ce secteur et tous ses projets ?")) {
            setSecteurs(secteurs.filter(s => s.id !== id));
        }
    };
    const handleAddProjet = (secteurId) => {
        const nom = window.prompt("Nom du nouveau projet associ├® :");
        if (nom) setSecteurs(secteurs.map(s => s.id === secteurId ? { ...s, projets: [...s.projets, nom] } : s));
    };

    // HANDLERS SERVICES
    const handleAddService = () => {
        const nom = window.prompt("Nom du nouveau service/prestation :");
        if (!nom) return;
        const categorie = window.prompt("Cat├®gorie strat├®gique (ex: Web, Ads, Branding) :");
        const prixStr = window.prompt("Prix standard en TND (ex: 1500) :");
        const prix = parseFloat(prixStr) || 0;
        setServices([...services, { id: `SRV_${Date.now()}`, nom, categorie: categorie || 'Autre', prix }]);
    };
    const handleDeleteService = (id) => {
        if (window.confirm("Supprimer ce service du catalogue ?")) {
            setServices(services.filter(s => s.id !== id));
        }
    };

    // Derived State for Client dropdown
    const allProjets = useMemo(() => {
        try {
            const parsed = getClients();
            return parsed.map(c => c.enseigne + (c.projet ? ` - ${c.projet}` : ''));
        } catch (e) {
            console.error("Erreur lecture clients", e);
        }
        return ['Acme Corp - Refonte Site E-commerce', 'TechSolutions Inc - Campagne Ads Q3'];
    }, []);

    // Get current clients to compute dynamic assignments per RH
    const clientsData = useMemo(() => {
        try {
            return getClients();
        } catch (e) {
            console.error("Erreur lecture clients pour RH", e);
        }
        return [];
    }, []);

    // HANDLERS RH
    const handleAddRH = () => {
        setEditingRH(null);
        setIsRHModalOpen(true);
    };

    const handleEditRH = (rh) => {
        setEditingRH(rh);
        setIsRHModalOpen(true);
    };

    const handleSaveRH = (rhData) => {
        if (editingRH) {
            setRhList(rhList.map(r => r.id === rhData.id ? rhData : r));
        } else {
            setRhList([...rhList, rhData]);
        }
    };

    const handleDeleteRH = (id) => {
        if (window.confirm("├ètes-vous s├╗r de vouloir supprimer cette personne ?")) {
            setRhList(rhList.filter(r => r.id !== id));
        }
    };

    // HANDLERS BACKUP & RESTORE
    const handleExportData = () => {
        try {
            const dataToExport = {};
            for (let i = 0; i < localStorage.length; i++) {
                const key = localStorage.key(i);
                if (key.startsWith('mynds_')) {
                    dataToExport[key] = localStorage.getItem(key);
                }
            }
            
            const dataStr = JSON.stringify(dataToExport, null, 2);
            const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
            
            const exportFileDefaultName = `Mynds_Backup_${new Date().toISOString().split('T')[0]}.json`;
            
            const linkElement = document.createElement('a');
            linkElement.setAttribute('href', dataUri);
            linkElement.setAttribute('download', exportFileDefaultName);
            linkElement.click();
        } catch (error) {
            console.error("Erreur lors de l'exportation:", error);
            alert("Une erreur est survenue lors de la cr├®ation de la sauvegarde.");
        }
    };

    const handleImportData = (event) => {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const importedData = JSON.parse(e.target.result);
                
                if (window.confirm("ATTENTION : L'importation d'une sauvegarde va ├®craser VOS DONN├ëES ACTUELLES. Voulez-vous vraiment continuer ?")) {
                    // Clear existing mynds_ keys to ensure clean restore
                    const keysToRemove = [];
                    for (let i = 0; i < localStorage.length; i++) {
                        const key = localStorage.key(i);
                        if (key && key.startsWith('mynds_')) {
                            keysToRemove.push(key);
                        }
                    }
                    keysToRemove.forEach(k => localStorage.removeItem(k));

                    // Restore full imported object
                    Object.keys(importedData).forEach(key => {
                        if (key.startsWith('mynds_')) {
                            localStorage.setItem(key, importedData[key]);
                        }
                    });

                    alert("­ƒÄë Sauvegarde restaur├®e avec succ├¿s ! L'application va se recharger.");
                    window.location.reload();
                }
            } catch (error) {
                console.error("Erreur d'importation:", error);
                alert("Le fichier s├®lectionn├® est invalide ou corrompu.");
            }
            // Reset the input
            if (fileInputRef.current) fileInputRef.current.value = '';
        };
        reader.readAsText(file);
    };

