            [clientName]: !prev[clientName]
        }));
    };

    // -- NOUVELLES CARTES KPI SIMPLIFI├ëES --
    const now = new Date();
    const todayMidnight = new Date(now.getFullYear(), now.getMonth(), now.getDate());

