                                                                    monthlyTotals[idx].unpaid += monthUnpaid;
                                                                    clientPaid += monthPaid;
                                                                    clientUnpaid += monthUnpaid;
                                                                    grandTotalPaid += monthPaid;
                                                                    grandTotalUnpaid += monthUnpaid;
                                                                }

                                                                const totalAmount = monthPaid + monthUnpaid;
                                                                let statusColor = 'transparent';
                                                                let bgStripes = 'none';

