                                                                    if (monthUnpaid === 0) { // All paid
                                                                        statusColor = 'rgba(16, 185, 129, 0.05)';
                                                                    } else if (monthPaid === 0) { // All unpaid
                                                                        statusColor = 'rgba(239, 68, 68, 0.05)';
