                                                                        statusColor = 'rgba(239, 68, 68, 0.03)';
                                                                        bgStripes = 'repeating-linear-gradient(45deg, rgba(16,185,129,0.03), rgba(16,185,129,0.03) 4px, rgba(239,68,68,0.03) 4px, rgba(239,68,68,0.03) 8px)';
                                                                    }
